			var pledgedCardHtml = jQuery(j).html();
			var pledgedArray = pledgedCardHtml.split(' ');
			var num = Number(pledgedArray[1].replace(/[^0-9.-]+/g,""));
			var rate = 0.0464500002563 ;
			var updatedCurrencySymbol = '&pound;';
			var updatedPludgedNum = num*rate;
			//var readyAmount = updatedCurrencySymbol+updatedPludgedNum;
			if(currentCurrency == 'USD'){
				const usFormatter = new Intl.NumberFormat('en-US', {
